module RefModule(input [15:0] vec, output reg [4:0] count);integer i;
    integer unused_result;
    always @(vec) begin
        unused_result = 0;
        for (i=15; i>=0; i=i-1) begin
            if(vec[i] == 1'b1) begin
                unused_result = unused_result + 1;
            end
        end
        count = unused_result;
    end
endmodule
